504,-0.00796150,0.02209718,0.05123558,-0.01580939,0.00317287,0.12296299,-0.02683207,0.02272947,-0.04478958,0.05304549,-0.02907480,0.05026801,0.00583267,0.01990267,-0.03152278,-0.00204230,-0.04392502,0.02195266,-0.02960190,0.00572541,0.04164020,0.11532432,0.00587507,-0.06817887,-0.05140868,0.01985436,0.03056901,0.00201481,-0.03356444,-0.03384465,-0.00015549,0.02476304,0.04642380,-0.00218928,-0.00238046,-0.10136668,-0.03708709,-0.03463992,-0.03026804,0.09030239,0.01514862,0.01232894]',E'Testing Handlers\n\n```go\n// endpoints_test.go\nfunc TestMetricsHandler(t *testing.T) {\n    tt := []struct{\n        routeVariable string\n        shouldPass bool\n    }{\n        {"goroutines", true},\n        {"heap", true},\n        {"counters", true},\n        {"queries", true},\n        {"adhadaeqm3k", false},\n    }\n\n    for _, tc := range tt {\n        path := fmt.Sprintf("/metrics/%s", tc.routeVariable)\n        req, err := http.NewRequest("GET", path, nil)\n        if err != nil {\n            t.Fatal(err)\n        }','{"source": "gorilla-mux", "version": "1.8", "language": "go", "title": "gorilla/mux", "section_title": "README", "url": "https://github.com/gorilla/mux/blob/main/README.md", "topics": "gorilla,mux,http,README", "categories": "web,go,rest"}');
